module top_module(
    input [63:0] input_data,
    input [3:0] control,
    output reg [63:0] data_out // Changed wire to reg
);always @(*) begin
    case(control)
        4'b0000: data_out = {input_data[62:0], 1'b0};
        4'b0001: data_out = {1'b0, input_data[63:1]};
        4'b0010: data_out = {input_data[61:0], 2'b00};
        4'b0011: data_out = {2'b00, input_data[63:2]};
        4'b0100: data_out = {input_data[60:0], 3'b000};
        4'b0101: data_out = {3'b000, input_data[63:3]};
        4'b0110: data_out = {input_data[59:0], 4'b0000};
        4'b0111: data_out = {4'b0000, input_data[63:4]};
        default: data_out = input_data;
    endcase
end

endmodule
